#include<cstdio>
using namespace std;

int main()
{
	int n,i,j;
	scanf("%d",&n);
	for(i=1;i<=n;i++)
	{
		for(j=1;j<=n;j++)
		{
			int s=0;
			if((j==1)||(j==n))
			{
				s=1;
				printf("|");
			}
			if(i==(n+1)/2)
			{
				if(s==0)
				{
					printf("-");
					s=1;	
				}
			}
			if(i==1 && j!=1 && j!=n || i==n && j!=1 && j!=n )
			{
				s=1;
				printf("-");
			}
			if(s==0)
			{
				printf("x");
			}
		}
		printf("\n");
	}
	return 0;
}
